const data = $('Obtener datos').item.json;
let iaTexto = '';
try { iaTexto = $json.candidates[0].content.parts[0].text; } catch (e) { iaTexto = typeof $json === 'string' ? $json : JSON.stringify($json); }
const fmt = (n) => '$' + Number(n||0).toLocaleString('es-EC');
const r = data.resumen || {};
const periodo = new Date(data.periodo?.hasta || Date.now()).toLocaleDateString('es-EC');
const kpi = (label,val) => `<td style='padding:10px;border:1px solid #eee;text-align:center'><div style='font-size:22px;font-weight:700;color:#0a0a0a'>${val}</div><div style='font-size:11px;color:#6b7280;text-transform:uppercase'>${label}</div></td>`;
const rank = (data.rankingVendedores||[]).map((v,i)=>`<tr><td style='padding:8px;border-bottom:1px solid #eee'>${i+1}. ${v.nombre}</td><td style='padding:8px;border-bottom:1px solid #eee;text-align:center'>${v.citas}</td><td style='padding:8px;border-bottom:1px solid #eee;text-align:center'>${v.ejecutadas}</td></tr>`).join('') || `<tr><td colspan='3' style='padding:8px;color:#6b7280'>Sin citas en el periodo</td></tr>`;
const props = (data.resumenPorPropiedad||[]).map(p=>`<tr><td style='padding:8px;border-bottom:1px solid #eee'>${p.titulo}</td><td style='padding:8px;border-bottom:1px solid #eee;text-align:center'>${p.interesados}</td><td style='padding:8px;border-bottom:1px solid #eee;text-align:center'>${p.contado}/${p.credito}</td><td style='padding:8px;border-bottom:1px solid #eee;text-align:center'>${p.visitas}</td><td style='padding:8px;border-bottom:1px solid #eee;text-align:right'>${fmt(p.ticketPromedio)}</td></tr>`).join('') || `<tr><td colspan='5' style='padding:8px;color:#6b7280'>Sin actividad</td></tr>`;
const html = `<!doctype html><html><body style='font-family:Arial,sans-serif;background:#fafafa;margin:0;padding:24px'><div style='max-width:680px;margin:0 auto;background:#fff;border:1px solid #eee'><div style='background:#0a0a0a;color:#fff;padding:24px'><div style='color:#c9a961;letter-spacing:.2em;font-size:11px;text-transform:uppercase'>LGEA Constructores</div><h1 style='margin:6px 0 0;font-size:22px'>Reporte semanal - ${periodo}</h1></div><div style='padding:24px'><table style='width:100%;border-collapse:collapse;margin-bottom:20px'><tr>${kpi('Citas',r.citasAgendadas??0)}${kpi('Ejecutadas',r.citasEjecutadas??0)}${kpi('Leads',r.leadsNuevos??0)}${kpi('Visitas',r.visitasPropiedades??0)}</tr></table><h2 style='font-size:15px;border-left:3px solid #c9a961;padding-left:8px'>Analisis con IA</h2><div style='color:#404040;line-height:1.6;font-size:14px'>${iaTexto}</div><h2 style='font-size:15px;border-left:3px solid #c9a961;padding-left:8px;margin-top:24px'>Ranking de vendedores</h2><table style='width:100%;border-collapse:collapse;font-size:13px'><tr style='text-align:left;color:#6b7280'><th style='padding:8px'>Vendedor</th><th style='padding:8px'>Citas</th><th style='padding:8px'>Ejecutadas</th></tr>${rank}</table><h2 style='font-size:15px;border-left:3px solid #c9a961;padding-left:8px;margin-top:24px'>Resumen por propiedad</h2><table style='width:100%;border-collapse:collapse;font-size:13px'><tr style='text-align:left;color:#6b7280'><th style='padding:8px'>Propiedad</th><th style='padding:8px'>Interes.</th><th style='padding:8px'>Cont/Cred</th><th style='padding:8px'>Visitas</th><th style='padding:8px;text-align:right'>Ticket</th></tr>${props}</table></div><div style='padding:16px;background:#0a0a0a;color:#6b7280;font-size:11px;text-align:center'>Generado automaticamente con n8n + Gemini</div></div></body></html>`;
return [{ json: { html, asunto: 'Reporte semanal LGEA - ' + periodo } }];
